import { initTRPC } from "@trpc/server";
import { z } from "zod";

const t = initTRPC.create();

const sleep = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));

export const appRouter = t.router({
  streamWords: t.procedure
    .input(z.void())
    .query(async function* () {
      const words = ["Hello", "streaming", "world"] as const;

      for (const word of words) {
        await sleep(100);
        yield word;
      }
    }),
});

export type AppRouter = typeof appRouter;

import { fetchRequestHandler } from "@trpc/server/adapters/fetch";

import { appRouter } from "@/server/trpc";

const handler = (request: Request) =>
  fetchRequestHandler({
    endpoint: "/api/trpc",
    req: request,
    router: appRouter,
    createContext: () => ({}),
  });

export { handler as GET, handler as POST };

"use client";

import { QueryClient } from "@tanstack/react-query";
import { createTRPCClient, httpBatchStreamLink } from "@trpc/client";

import type { AppRouter } from "@/server/trpc";

export const queryClient = new QueryClient();

export const trpcClient = createTRPCClient<AppRouter>({
  links: [
    httpBatchStreamLink({
      url: "/api/trpc",
    }),
  ],
});

"use client";

import { useEffect, useState } from "react";

import { trpcClient } from "@/lib/trpc-client";

export default function Home() {
  const [words, setWords] = useState<string[]>([]);

  useEffect(() => {
    let cancelled = false;

    const stream = async () => {
      const response = await trpcClient.streamWords.query();

      for await (const word of response) {
        if (cancelled) {
          break;
        }

        setWords((current) => [...current, word]);
      }
    };

    stream().catch((error: unknown) => {
      console.error("Failed to stream words", error);
    });

    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <main
      style={{
        minHeight: "100vh",
        display: "grid",
        placeItems: "center",
        padding: "2rem",
      }}
    >
      <section
        style={{
          width: "100%",
          maxWidth: "42rem",
          padding: "2rem",
          borderRadius: "1rem",
          border: "1px solid rgba(127, 127, 127, 0.2)",
          background: "rgba(127, 127, 127, 0.08)",
          textAlign: "center",
        }}
      >
        <p style={{ fontSize: "0.875rem", opacity: 0.7, marginBottom: "0.75rem" }}>
          tRPC v11 streaming demo
        </p>
        <h1 style={{ fontSize: "2rem", marginBottom: "1rem" }}>Streaming response</h1>
        <p style={{ fontSize: "1.25rem", lineHeight: 1.6 }}>{words.join(" ")}</p>
      </section>
    </main>
  );
}

